/* VCD dumping routines */

unsigned int MOD_mkBoot_ROM::dump_VCD_defs(unsigned int levels)
{
  vcd_write_scope_start(sim_hdl, inst_name);
  vcd_num = vcd_reserve_ids(sim_hdl, 22u);
  unsigned int num = vcd_num;
  for (unsigned int clk = 0u; clk < bk_num_clocks(sim_hdl); ++clk)
    vcd_add_clock_def(sim_hdl, this, bk_clock_name(sim_hdl, clk), bk_clock_vcd_num(sim_hdl, clk));
  vcd_write_def(sim_hdl, bk_clock_vcd_num(sim_hdl, __clk_handle_0), "CLK", 1u);
  vcd_write_def(sim_hdl, num++, "RST_N", 1u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "base__h6415", 64u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "lim__h6417", 64u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "slavePortShim_shim_arff_first_BITS_100_TO_93_8_ETC___d1233", 75u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "slavePortShim_shim_arff_first____d8", 101u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "slavePortShim_shim_awff_first____d1244", 101u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "slavePortShim_shim_bff_i_notEmpty____d1297", 1u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "slavePortShim_shim_rff_i_notEmpty____d1298", 1u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "v__h6591", 32u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "v__h915", 32u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "slave_ar_put_val", 101u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "slave_aw_put_val", 101u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "slave_r_peek", 75u);
  vcd_set_clock(sim_hdl, num, __clk_handle_0);
  vcd_write_def(sim_hdl, num++, "slave_w_put_val", 73u);
  num = INST_rg_addr_base.dump_VCD_defs(num);
  num = INST_rg_addr_lim.dump_VCD_defs(num);
  num = INST_rg_module_ready.dump_VCD_defs(num);
  num = INST_slavePortShim_shim_arff.dump_VCD_defs(num);
  num = INST_slavePortShim_shim_awff.dump_VCD_defs(num);
  num = INST_slavePortShim_shim_bff.dump_VCD_defs(num);
  num = INST_slavePortShim_shim_rff.dump_VCD_defs(num);
  num = INST_slavePortShim_shim_wff.dump_VCD_defs(num);
  vcd_write_scope_end(sim_hdl);
  return num;
}

void MOD_mkBoot_ROM::dump_VCD(tVCDDumpType dt, unsigned int levels, MOD_mkBoot_ROM &backing)
{
  vcd_defs(dt, backing);
  vcd_prims(dt, backing);
}

void MOD_mkBoot_ROM::vcd_defs(tVCDDumpType dt, MOD_mkBoot_ROM &backing)
{
  unsigned int num = vcd_num;
  if (dt == VCD_DUMP_XS)
  {
    vcd_write_x(sim_hdl, num++, 1u);
    vcd_write_x(sim_hdl, num++, 64u);
    vcd_write_x(sim_hdl, num++, 64u);
    vcd_write_x(sim_hdl, num++, 75u);
    vcd_write_x(sim_hdl, num++, 101u);
    vcd_write_x(sim_hdl, num++, 101u);
    vcd_write_x(sim_hdl, num++, 1u);
    vcd_write_x(sim_hdl, num++, 1u);
    vcd_write_x(sim_hdl, num++, 32u);
    vcd_write_x(sim_hdl, num++, 32u);
    vcd_write_x(sim_hdl, num++, 101u);
    vcd_write_x(sim_hdl, num++, 101u);
    vcd_write_x(sim_hdl, num++, 75u);
    vcd_write_x(sim_hdl, num++, 73u);
  }
  else
    if (dt == VCD_DUMP_CHANGES)
    {
      if ((backing.PORT_RST_N) != PORT_RST_N)
      {
	vcd_write_val(sim_hdl, num, PORT_RST_N, 1u);
	backing.PORT_RST_N = PORT_RST_N;
      }
      ++num;
      if ((backing.DEF_base__h6415) != DEF_base__h6415)
      {
	vcd_write_val(sim_hdl, num, DEF_base__h6415, 64u);
	backing.DEF_base__h6415 = DEF_base__h6415;
      }
      ++num;
      if ((backing.DEF_lim__h6417) != DEF_lim__h6417)
      {
	vcd_write_val(sim_hdl, num, DEF_lim__h6417, 64u);
	backing.DEF_lim__h6417 = DEF_lim__h6417;
      }
      ++num;
      if ((backing.DEF_slavePortShim_shim_arff_first_BITS_100_TO_93_8_ETC___d1233) != DEF_slavePortShim_shim_arff_first_BITS_100_TO_93_8_ETC___d1233)
      {
	vcd_write_val(sim_hdl, num, DEF_slavePortShim_shim_arff_first_BITS_100_TO_93_8_ETC___d1233, 75u);
	backing.DEF_slavePortShim_shim_arff_first_BITS_100_TO_93_8_ETC___d1233 = DEF_slavePortShim_shim_arff_first_BITS_100_TO_93_8_ETC___d1233;
      }
      ++num;
      if ((backing.DEF_slavePortShim_shim_arff_first____d8) != DEF_slavePortShim_shim_arff_first____d8)
      {
	vcd_write_val(sim_hdl, num, DEF_slavePortShim_shim_arff_first____d8, 101u);
	backing.DEF_slavePortShim_shim_arff_first____d8 = DEF_slavePortShim_shim_arff_first____d8;
      }
      ++num;
      if ((backing.DEF_slavePortShim_shim_awff_first____d1244) != DEF_slavePortShim_shim_awff_first____d1244)
      {
	vcd_write_val(sim_hdl, num, DEF_slavePortShim_shim_awff_first____d1244, 101u);
	backing.DEF_slavePortShim_shim_awff_first____d1244 = DEF_slavePortShim_shim_awff_first____d1244;
      }
      ++num;
      if ((backing.DEF_slavePortShim_shim_bff_i_notEmpty____d1297) != DEF_slavePortShim_shim_bff_i_notEmpty____d1297)
      {
	vcd_write_val(sim_hdl, num, DEF_slavePortShim_shim_bff_i_notEmpty____d1297, 1u);
	backing.DEF_slavePortShim_shim_bff_i_notEmpty____d1297 = DEF_slavePortShim_shim_bff_i_notEmpty____d1297;
      }
      ++num;
      if ((backing.DEF_slavePortShim_shim_rff_i_notEmpty____d1298) != DEF_slavePortShim_shim_rff_i_notEmpty____d1298)
      {
	vcd_write_val(sim_hdl, num, DEF_slavePortShim_shim_rff_i_notEmpty____d1298, 1u);
	backing.DEF_slavePortShim_shim_rff_i_notEmpty____d1298 = DEF_slavePortShim_shim_rff_i_notEmpty____d1298;
      }
      ++num;
      if ((backing.DEF_v__h6591) != DEF_v__h6591)
      {
	vcd_write_val(sim_hdl, num, DEF_v__h6591, 32u);
	backing.DEF_v__h6591 = DEF_v__h6591;
      }
      ++num;
      if ((backing.DEF_v__h915) != DEF_v__h915)
      {
	vcd_write_val(sim_hdl, num, DEF_v__h915, 32u);
	backing.DEF_v__h915 = DEF_v__h915;
      }
      ++num;
      if ((backing.PORT_slave_ar_put_val) != PORT_slave_ar_put_val)
      {
	vcd_write_val(sim_hdl, num, PORT_slave_ar_put_val, 101u);
	backing.PORT_slave_ar_put_val = PORT_slave_ar_put_val;
      }
      ++num;
      if ((backing.PORT_slave_aw_put_val) != PORT_slave_aw_put_val)
      {
	vcd_write_val(sim_hdl, num, PORT_slave_aw_put_val, 101u);
	backing.PORT_slave_aw_put_val = PORT_slave_aw_put_val;
      }
      ++num;
      if ((backing.PORT_slave_r_peek) != PORT_slave_r_peek)
      {
	vcd_write_val(sim_hdl, num, PORT_slave_r_peek, 75u);
	backing.PORT_slave_r_peek = PORT_slave_r_peek;
      }
      ++num;
      if ((backing.PORT_slave_w_put_val) != PORT_slave_w_put_val)
      {
	vcd_write_val(sim_hdl, num, PORT_slave_w_put_val, 73u);
	backing.PORT_slave_w_put_val = PORT_slave_w_put_val;
      }
      ++num;
    }
    else
    {
      vcd_write_val(sim_hdl, num++, PORT_RST_N, 1u);
      backing.PORT_RST_N = PORT_RST_N;
      vcd_write_val(sim_hdl, num++, DEF_base__h6415, 64u);
      backing.DEF_base__h6415 = DEF_base__h6415;
      vcd_write_val(sim_hdl, num++, DEF_lim__h6417, 64u);
      backing.DEF_lim__h6417 = DEF_lim__h6417;
      vcd_write_val(sim_hdl, num++, DEF_slavePortShim_shim_arff_first_BITS_100_TO_93_8_ETC___d1233, 75u);
      backing.DEF_slavePortShim_shim_arff_first_BITS_100_TO_93_8_ETC___d1233 = DEF_slavePortShim_shim_arff_first_BITS_100_TO_93_8_ETC___d1233;
      vcd_write_val(sim_hdl, num++, DEF_slavePortShim_shim_arff_first____d8, 101u);
      backing.DEF_slavePortShim_shim_arff_first____d8 = DEF_slavePortShim_shim_arff_first____d8;
      vcd_write_val(sim_hdl, num++, DEF_slavePortShim_shim_awff_first____d1244, 101u);
      backing.DEF_slavePortShim_shim_awff_first____d1244 = DEF_slavePortShim_shim_awff_first____d1244;
      vcd_write_val(sim_hdl, num++, DEF_slavePortShim_shim_bff_i_notEmpty____d1297, 1u);
      backing.DEF_slavePortShim_shim_bff_i_notEmpty____d1297 = DEF_slavePortShim_shim_bff_i_notEmpty____d1297;
      vcd_write_val(sim_hdl, num++, DEF_slavePortShim_shim_rff_i_notEmpty____d1298, 1u);
      backing.DEF_slavePortShim_shim_rff_i_notEmpty____d1298 = DEF_slavePortShim_shim_rff_i_notEmpty____d1298;
      vcd_write_val(sim_hdl, num++, DEF_v__h6591, 32u);
      backing.DEF_v__h6591 = DEF_v__h6591;
      vcd_write_val(sim_hdl, num++, DEF_v__h915, 32u);
      backing.DEF_v__h915 = DEF_v__h915;
      vcd_write_val(sim_hdl, num++, PORT_slave_ar_put_val, 101u);
      backing.PORT_slave_ar_put_val = PORT_slave_ar_put_val;
      vcd_write_val(sim_hdl, num++, PORT_slave_aw_put_val, 101u);
      backing.PORT_slave_aw_put_val = PORT_slave_aw_put_val;
      vcd_write_val(sim_hdl, num++, PORT_slave_r_peek, 75u);
      backing.PORT_slave_r_peek = PORT_slave_r_peek;
      vcd_write_val(sim_hdl, num++, PORT_slave_w_put_val, 73u);
      backing.PORT_slave_w_put_val = PORT_slave_w_put_val;
    }
}

void MOD_mkBoot_ROM::vcd_prims(tVCDDumpType dt, MOD_mkBoot_ROM &backing)
{
  INST_rg_addr_base.dump_VCD(dt, backing.INST_rg_addr_base);
  INST_rg_addr_lim.dump_VCD(dt, backing.INST_rg_addr_lim);
  INST_rg_module_ready.dump_VCD(dt, backing.INST_rg_module_ready);
  INST_slavePortShim_shim_arff.dump_VCD(dt, backing.INST_slavePortShim_shim_arff);
  INST_slavePortShim_shim_awff.dump_VCD(dt, backing.INST_slavePortShim_shim_awff);
  INST_slavePortShim_shim_bff.dump_VCD(dt, backing.INST_slavePortShim_shim_bff);
  INST_slavePortShim_shim_rff.dump_VCD(dt, backing.INST_slavePortShim_shim_rff);
  INST_slavePortShim_shim_wff.dump_VCD(dt, backing.INST_slavePortShim_shim_wff);
}
